+  const args = argv.slice(1);
+  const normalized = args.map((a) => a.replace(/\//g, "\\"));
+  if (normalized.length === 0) {
+    return "^\x00\x00$";
+  }
+  const joined = normalized.join("\x00");
+  return `^${escapeRegExpLiteral(joined)}\x00$`;
